-- ============================================================
-- DLM_JOB_PII_INIT : PII 파기 JOB 초기 데이터 (POLICY3 / DAON / CORE)
-- ============================================================
-- 3단계 개인정보 파기(PII_POLICY3) 의 DAON CORE 영역 JOB 정의를
-- 일괄 등록하는 초기 스크립트입니다.
--
-- [등록 JOB]
--   PII_POLICY3_DAON_CORE_DELETE : DAON_CORE 3단계 파기 (Archive → Delete → Broadcast → Finish)
--   PII_POLICY3_DAON_CORE_UPDATE : DAON_CORE 3단계 파기 (Extract → Keymap → Archive → Update)
--   ※ DELETE 는 UPDATE 의 후속(PRE-DEP) — TBL_PIIJOBWAIT 로 의존성 표시
--
-- [등록 테이블]
--   1. TBL_PIIJOB              : JOB 헤더 (스케줄/소유자/정책)
--   2. TBL_PIIJOBWAIT          : JOB 간 선행 의존성
--   3. TBL_PIISTEP             : JOB 별 단계(STEP) 정의
--   4. TBL_PIISTEPTABLE        : STEP 별 처리 테이블/SQL 정의
--   5. TBL_PIISTEPTABLEUPDATE  : UPDATE STEP 의 컬럼 마스킹 정의
--
-- [실행 순서 주의]
--   기존 데이터를 JOBID 스코프로만 삭제하므로 다른 JOB 에는 영향 없음.
--   FK 는 없으나 PK 참조 순서대로 INSERT (JOB → STEP → STEPTABLE → STEPTABLEUPDATE).
--
-- ============================================================
-- 사이트별 배포 시 아래 변수를 해당 사이트 값으로 치환(Replace All)하세요.
--
--   COTDL     -> DLM 스키마명         (기본값: COTDL)
--   DAON      -> 원천 DB 명           (예: DAON)
--   COOWNSER  -> 원천 OWNER (계약)    (예: COOWNSER)
--   piiCOOWNSER -> 분리보관 스키마    (예: PIICOOWNSER)
--   #KEYMAP_ID  -> 런타임 치환 (KEYMAP_ID)
--   #BASEDATE   -> 런타임 치환 (BASEDATE)
--   #ORDERID    -> 런타임 치환 (ORDERID)
--   admin -> 등록/수정 사용자 ID (기본값: admin)
-- ============================================================


-- ────────────────────────────────────────────────────────────
-- 기존 데이터 삭제 (JOBID 스코프 — 다른 JOB 영향 없음)
-- 자식 테이블 → 부모 테이블 순서로 삭제
-- ────────────────────────────────────────────────────────────
DELETE FROM COTDL.TBL_PIISTEPTABLEUPDATE WHERE JOBID IN ('PII_POLICY3_DAON_CORE_DELETE','PII_POLICY3_DAON_CORE_UPDATE');
DELETE FROM COTDL.TBL_PIISTEPTABLE       WHERE JOBID IN ('PII_POLICY3_DAON_CORE_DELETE','PII_POLICY3_DAON_CORE_UPDATE');
DELETE FROM COTDL.TBL_PIISTEP            WHERE JOBID IN ('PII_POLICY3_DAON_CORE_DELETE','PII_POLICY3_DAON_CORE_UPDATE');
DELETE FROM COTDL.TBL_PIIJOBWAIT         WHERE JOBID IN ('PII_POLICY3_DAON_CORE_DELETE','PII_POLICY3_DAON_CORE_UPDATE');
DELETE FROM COTDL.TBL_PIIJOB             WHERE JOBID IN ('PII_POLICY3_DAON_CORE_DELETE','PII_POLICY3_DAON_CORE_UPDATE');


