	 ('PII_POLICY3_DAON_CORE_UPDATE','1','EXE_ARCHIVE','DAON','COOWNSER','ACTEUR','','','ARCHIVE','','',NULL,NULL,1,10,10,NULL,'ACTID','ACTID','KEY_ACTID',NULL,NULL,'select #ORDERID AS PII_ORDER_ID, B.BASEDATE AS PII_BASE_DATE, B.CUSTID AS PII_CUST_ID,''PII_POLICY3_DAON_CORE_UPDATE'' AS PII_JOB_ID, B.EXPECTED_ARC_DEL_DATE AS PII_DESTRUCT_DATE , A.* FROM COOWNSER.ACTEUR A, COTDL.TBL_PIIKEYMAP B WHERE B.KEY_NAME = ''KEY_ACTID'' AND B.KEYMAP_ID = ''#KEYMAP_ID'' AND B.BASEDATE = TO_DATE(''#BASEDATE'',''yyyy/mm/dd'') AND A.ACTID = B.VAL1','insert into piiCOOWNSER.ACTEUR select #ORDERID AS PII_ORDER_ID, B.BASEDATE AS PII_BASE_DATE, B.CUSTID AS PII_CUST_ID,''PII_POLICY3_DAON_CORE_UPDATE'' AS PII_JOB_ID, B.EXPECTED_ARC_DEL_DATE AS PII_DESTRUCT_DATE , A.* FROM COOWNSER.ACTEUR A, COTDL.TBL_PIIKEYMAP B WHERE B.KEY_NAME = ''KEY_ACTID'' AND B.KEYMAP_ID = ''#KEYMAP_ID'' AND B.BASEDATE = TO_DATE(''#BASEDATE'',''yyyy/mm/dd'') AND A.ACTID = B.VAL1',NULL,NULL,NULL,'',NULL,'2026-03-17 10:55:20','2026-03-17 10:55:20','','admin',NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 ('PII_POLICY3_DAON_CORE_UPDATE','1','EXE_ARCHIVE','DAON','COOWNSER','ACTASSENT','','','ARCHIVE','','',NULL,NULL,1,20,10,NULL,'ACTID,AASORDER','ACTID','KEY_ACTID',NULL,NULL,'select #ORDERID AS PII_ORDER_ID, B.BASEDATE AS PII_BASE_DATE, B.CUSTID AS PII_CUST_ID,''PII_POLICY3_DAON_CORE_UPDATE'' AS PII_JOB_ID, B.EXPECTED_ARC_DEL_DATE AS PII_DESTRUCT_DATE , A.* FROM COOWNSER.ACTASSENT A, COTDL.TBL_PIIKEYMAP B WHERE B.KEY_NAME = ''KEY_ACTID'' AND B.KEYMAP_ID = ''#KEYMAP_ID'' AND B.BASEDATE = TO_DATE(''#BASEDATE'',''yyyy/mm/dd'') AND A.ACTID = B.VAL1','insert into piiCOOWNSER.ACTASSENT select #ORDERID AS PII_ORDER_ID, B.BASEDATE AS PII_BASE_DATE, B.CUSTID AS PII_CUST_ID,''PII_POLICY3_DAON_CORE_UPDATE'' AS PII_JOB_ID, B.EXPECTED_ARC_DEL_DATE AS PII_DESTRUCT_DATE , A.* FROM COOWNSER.ACTASSENT A, COTDL.TBL_PIIKEYMAP B WHERE B.KEY_NAME = ''KEY_ACTID'' AND B.KEYMAP_ID = ''#KEYMAP_ID'' AND B.BASEDATE = TO_DATE(''#BASEDATE'',''yyyy/mm/dd'') AND A.ACTID = B.VAL1',NULL,NULL,NULL,'',NULL,'2026-03-17 10:55:20','2026-03-17 10:55:20','','admin',NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 ('PII_POLICY3_DAON_CORE_UPDATE','1','EXE_EXTRACT','DAON','COOWNHYP','DTBB1230',NULL,'ADD','EXTRACT','','',NULL,NULL,1,100,10,NULL,'파기대상 고객 추출','','',NULL,NULL,NULL,'insert into COTDL.TBL_PIIEXTRACT (orderid, jobid, actid, custid, basedate, exclude_reason, actrole_end_date, archive_date, delete_date, restore_date, arc_del_date, last_base_date, expected_arc_del_date, cust_nm, birth_dt, address, rsdnt_altrntv_id, cust_pin, inst_cd, regdate, upddate, reguserid, upduserid)
select
	''#ORDERID'' as orderid,
	''#JOBID'' as jobid,
	custid as actid,
	custid as custid,
	TO_DATE(''#BASEDATE'',''yyyy/mm/dd'') as basedate,
	null as exclude_reason,
	null as actrole_end_date,
	null as archive_date,  -- this column is set in EXE_FINISH
	null as delete_date,   -- this column is set in EXE_FINISH
	null as restore_date,
	null as arc_del_date,
	last_base_date as last_base_date,
	#ARC_DEL_DEADLINE as expected_arc_del_date,
	cust_nm as cust_nm,
	birth_dt as birth_dt,
	address as address,
	null as rsdnt_altrntv_id,
	null as cust_pin,
	''DGBCAP''as inst_cd,
	sysdate as regdate,
	sysdate as upddate,
	''admin'' as reguserid,
	''admin'' as upduserid
from (
		SELECT ACT_ID as custid
		, ACT_ID||''님'' as cust_nm
		, ''19810808'' as birth_dt
		, ''서울시 마포구 서강로9길 ****'' as address
		, (sysdate-(90+rownum)) as last_base_date
		FROM COOWNHYP.DTBB1230
		WHERE 1=1
		AND CUST_INFO_DSTU_RSN_CD = ''02'' AND CSIF_DSTU_EXCL_RSN_CD is null
        order by ACT_ID
	) t
where 1=1
  and last_base_date < #DEL_DEADLINE
  and rownum <= #DLM_EXTRACT_MAX_CNT

	  ',NULL,NULL,NULL,'',NULL,'2026-03-17 10:55:20','2026-03-17 10:55:20','admin','admin',NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 ('PII_POLICY3_DAON_CORE_UPDATE','1','EXE_EXTRACT','DAON','COTDL','TBL_PIIEXTRACT',NULL,'EXCLUDE','EXTRACT',NULL,NULL,NULL,NULL,1,200,10,NULL,'5일내 복원 고객 제외',NULL,NULL,NULL,NULL,'  ','delete from cotdl.TBL_PIIEXTRACT a where jobid = ''#JOBID'' and orderid=#ORDERID AND exists (select 1 from cotdl.TBL_PIIEXTRACT b WHERE a.CUSTID = b.CUSTID AND b.EXCLUDE_REASON = ''RESTORE'' AND b.RESTORE_DATE > sysdate-5)',NULL,NULL,NULL,NULL,NULL,'2026-03-17 10:55:20','2026-03-17 10:55:20',NULL,'admin',NULL,NULL,NULL,NULL,NULL,NULL,NULL),
